#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) meke_pair(x,y);
#define inf 0x3f3f3f3f
using namespace std;
inline int read(){
    int x=0,f=1;
    char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    while(ch>='0'&&ch<='9')x=x*10+ch-'0',ch=getchar();
    return x*f;
}
void write(int x){
    if(x<0)putchar('-'),x=-x;
    if(x>9)write(x/10);
    putchar(x%10+'0');return;
}
int n,a,b,t=0;
priority_queue<int> q;
int main(void)
{
    n=read(),a=read(),b=read();
    for(int i=1;i<=n;++i)
    {
        q.push(read());
    }
    while(q.top()>a*t)
    {
        int now=q.top();
        q.pop(),++t;
        q.push(now-b);
    }
    write(t);
    return false;
}
